parameters.jsCode:
// FIRMS area API returns CSV with a header row. An empty body or
// header-only response means no hotspots — a valid state.
const text = ($input.first().json.data ?? '').trim();
const lines = text.split(/\r?\n/).filter(Boolean);
if (lines.length <= 1) {
  return [{ json: { empty: true, run_key: $execution.id } }];
}
const header = lines[0].split(',');
const col = (row, name) => row[header.indexOf(name)];
const rows = [];
for (const line of lines.slice(1)) {
  const r = line.split(',');
  const lat = parseFloat(col(r, 'latitude'));
  const lon = parseFloat(col(r, 'longitude'));
  const date = col(r, 'acq_date');            // YYYY-MM-DD
  const time = String(col(r, 'acq_time')).padStart(4, '0'); // HHMM
  const observedAt = `${date}T${time.slice(0, 2)}:${time.slice(2)}:00Z`;
  rows.push({
    source_id: 'nasa-firms',
    layer: 'fires',
    external_ref: `${col(r, 'satellite')}-${lat}-${lon}-${observedAt}`,
    observed_at: observedAt,
    lon, lat,
    values: {
      confidence: col(r, 'confidence'),
      frp_mw: parseFloat(col(r, 'frp')),
      satellite: col(r, 'satellite'),
    },
    run_key: $execution.id,
  });
}
return rows.map(r2 => ({ json: r2 }));

